import java.io.*;import java.util.*;class Main{static int solve(int[][]trans){HashMap<Integer,Integer>bal=new HashMap<>();for(int[]t:trans){bal.put(t[0],bal.getOrDefault(t[0],0)-t[2]);bal.put(t[1],bal.getOrDefault(t[1],0)+t[2]);}ArrayList<Integer>debts=new ArrayList<>();for(int v:bal.values())if(v!=0)debts.add(v);return dfs(debts,0);}static int dfs(ArrayList<Integer>d,int i){while(i<d.size()&&d.get(i)==0)i++;if(i==d.size())return 0;int best=1<<30;HashSet<Integer>seen=new HashSet<>();for(int j=i+1;j<d.size();j++)if(d.get(i)*d.get(j)<0&&!seen.contains(d.get(j))){seen.add(d.get(j));d.set(j,d.get(j)+d.get(i));best=Math.min(best,1+dfs(d,i+1));d.set(j,d.get(j)-d.get(i));if(d.get(j)+d.get(i)==0)break;}return best;}public static void main(String[]args)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[]v=text.split("\\s+");int idx=0,t=Integer.parseInt(v[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int m=Integer.parseInt(v[idx++]);int[][]trans=new int[m][3];for(int i=0;i<m;i++)for(int j=0;j<3;j++)trans[i][j]=Integer.parseInt(v[idx++]);if(tc>0)out.append("\n\n");out.append(solve(trans));}System.out.print(out);}}
